/**
 * @class krInput
 *
 * @desc krInput Directive
 *
 */

/**
 * krInput Directive
 *
 * @name directive
 *
 * @private
 * @memberOf krInput
 *
 */

/**
 * @alias directive
 *
 * @memberOf krInput
 *
 */

function _directive() {

    return {
        scope: false,
        require: 'ngModel',
        restrict: 'A',
        link: function ($scope, iElement, iAttrs, ngModel){

            iElement.on('keyup', function(){

                ngModel.$setViewValue(iElement.val() + '');

                $scope.$apply();
            });
        }
    };
}

module.exports = {
    directive: {
        name: 'krInput',
        $inject: [],
        constructor: _directive
    }
};
